module top_module(
    //# {{data|Data Signals}}
    input  A1  ,
    input  A2  ,
    input  A3  ,
    input  B1  ,
    input  C1  ,
    output X   ,

    //# {{power|Power}}
    input  VPWR,
    input  VGND
);wire invalid_result, temp2;

    assign invalid_result = B1 ? (A1 | A2) : 1'b0;
    assign temp2 = ~B1 & C1 ? (A2 & A3) : 1'b0;

    assign X = invalid_result ^ temp2 ^ (~B1 & ~C1 ? A1 ^ A2 ^ A3 : 1'b0);

endmodule
